// Normalize input from GHL job-completed trigger
const body = $json.body || $json;
const data = {
  clientGhlKey: body.clientGhlKey || body.ghlKey || body.location_token || '',
  locationId: body.locationId || body.location_id || '',
  contactId: body.contactId || body.contact_id || '',
  contactName: body.contact_name || body.firstName || body.first_name || 'Cliente',
  contactEmail: body.contact_email || body.email || '',
  contactPhone: body.contact_phone || body.phone || '',
  businessName: body.business_name || body.location_name || 'Nosso negocio',
  reviewLink: body.review_link || body.google_review_link || '',
  language: (body.language || 'pt').toLowerCase()
};

const firstName = data.contactName.split(' ')[0];

// Build localized SMS body — kept under 160 chars to stay 1-segment
const smsTemplates = {
  pt: `Oi ${firstName}! Obrigado por escolher a ${data.businessName}. Pode reservar 30s pra deixar uma avaliacao no Google? ${data.reviewLink} Significa muito pra gente!`,
  en: `Hi ${firstName}! Thanks for choosing ${data.businessName}. Could you spare 30 seconds to leave us a Google review? ${data.reviewLink} It means the world to us!`,
  es: `Hola ${firstName}! Gracias por elegir a ${data.businessName}. Te tomarias 30 segundos para dejarnos una resena en Google? ${data.reviewLink} Significa mucho para nosotros!`
};

const emailTemplates = {
  pt: { subject: `${firstName}, sua opiniao vale ouro pra ${data.businessName}`, body: `<p>Oi ${firstName},</p><p>Foi um prazer atender voce na <strong>${data.businessName}</strong>. Sua opiniao ajuda a gente a continuar entregando o melhor servico — e ajuda outras pessoas a encontrarem a gente.</p><p style="margin:24px 0;"><a href="${data.reviewLink}" style="background:#1a237e;color:#fff;padding:14px 28px;border-radius:8px;text-decoration:none;font-weight:bold;">Deixar minha avaliacao no Google</a></p><p>Demora menos de 1 minuto. Obrigado pela confianca!</p>` },
  en: { subject: `${firstName}, your feedback means everything to ${data.businessName}`, body: `<p>Hi ${firstName},</p><p>Thank you for choosing <strong>${data.businessName}</strong>. Your feedback helps us deliver better service — and helps other people find us when they need it most.</p><p style="margin:24px 0;"><a href="${data.reviewLink}" style="background:#1a237e;color:#fff;padding:14px 28px;border-radius:8px;text-decoration:none;font-weight:bold;">Leave my Google review</a></p><p>Takes under a minute. Thanks for trusting us!</p>` },
  es: { subject: `${firstName}, tu opinion vale mucho para ${data.businessName}`, body: `<p>Hola ${firstName},</p><p>Gracias por elegir a <strong>${data.businessName}</strong>. Tu opinion nos ayuda a seguir entregando el mejor servicio.</p><p style="margin:24px 0;"><a href="${data.reviewLink}" style="background:#1a237e;color:#fff;padding:14px 28px;border-radius:8px;text-decoration:none;font-weight:bold;">Dejar mi resena en Google</a></p><p>Toma menos de un minuto. Gracias por la confianza!</p>` }
};

const lang = ['pt', 'en', 'es'].includes(data.language) ? data.language : 'pt';
return [{ json: { ...data, smsBody: smsTemplates[lang], emailSubject: emailTemplates[lang].subject, emailBody: emailTemplates[lang].body, lang } }];
